import React, { useState } from 'react';
import './App.css';
import { Route, Routes } from 'react-router-dom'; 
import Main_Page from './Main_Page'; 
import Diarypage from './diarypage'; 
import Modal from './modal';

function App() {
  const [isDiarypageOpen, setIsDiarypageOpen] = useState(false);

  const openDiarypage = () => setIsDiarypageOpen(true);
  const closeDiarypage = () => setIsDiarypageOpen(false);

  return (
    <>
      {/* 여기서는 Router를 사용하지 않고 Diarypage.js에서 라우팅을 관리하도록 함 */}
      <Routes>
        <Route path="/" element={<Diarypage openDiarypage={openDiarypage} />} />
        {/* Diarypage에 대한 라우트는 Diarypage.js에서 직접 관리 */}
      </Routes>

      {/* Diarypage은 App.js 내에서 라우터 내에서 관리 */}
      <Diarypage isOpen={isDiarypageOpen} onClose={closeDiarypage} />
    </>
  );
}

export default App;
